import React from 'react'
import useTreeStore from './useTreeStore'
import { GoPencil, GoChevronRight, GoChevronDown } from "react-icons/go";
export const TYPE = {
    FOLDER: 'folder',
    FILE: 'file'
}
function TreeNode({ name, id, type, children, isExpanded }) {
    const expandedIds = useTreeStore((state) => state.expandedIds)
    const setExpandedIds = useTreeStore((state) => state.setExpandedIds)
    const showChildren = children && children.length > 0 && expandedIds[id]

    function renderChildren() {
        return (children.map(({ name, id, type, children }) => {
            return (
                <TreeNode key={id} name={name} type={type} children={children} isExpanded={isExpanded} />
            )
        }))
    }

    function renderer(name, type, isExpanded) {
        if (type === TYPE.FOLDER) {
            return (<div>
                <span>{name}</span>
                {isExpanded ? <GoChevronDown /> : <GoChevronRight />}
            </div>)
        } else {
            return <>
                <span>{name}</span>
            </>
        }
    }

    function clickHandler(id) {
        setExpandedIds(id)
    }

    return (
        <>
            <li key={id}>
                <button className='list-btn' onClick={() => clickHandler(id)}>{renderer(name, type, isExpanded)}</button>
                <button onClick={() => handleEdit(id)}><GoPencil /></button>

            </li>
            <ul className='folder'>{showChildren && renderChildren()}</ul>
        </>)

}

export default TreeNode
